import React, {
    type Ref,
    useCallback,
    useEffect,
    useImperativeHandle,
    useRef,
    useState,
} from "react";
import {Pressable, StyleSheet, ActivityIndicator, View} from "react-native";
import Animated, {
    FadeIn,
    FadeOut,
    SlideInUp,
    SlideInDown,
    SlideOutUp,
    SlideOutDown,
    Layout,
} from "react-native-reanimated";
import {useSafeAreaInsets} from "react-native-safe-area-context";
import {Text} from "../../_compat";
import type {
    IKitsToastRef,
    IToastFunction,
    IToastParams,
    ToastPosition,
    ToastSeverity,
    ToastSize,
} from "@lmb-it/kitsconcerto-types";
import {useKitsTheme} from "../../contexts/Theme";

interface ToastItem {
    id: number;
    severity: ToastSeverity;
    summary: string;
    body?: string;
    position: ToastPosition;
    size: ToastSize;
    sticky?: boolean;
}

let toastIdCounter = 0;
const LIFE = 3000;

const SIZE_CONFIG: Record<ToastSize, { paddingV: number; paddingH: number; summarySize: number; bodySize: number; accentWidth: number; closeSize: number; minW: number }> = {
    sm: {paddingV: 8, paddingH: 10, summarySize: 12, bodySize: 10, accentWidth: 3, closeSize: 14, minW: 200},
    md: {paddingV: 12, paddingH: 14, summarySize: 14, bodySize: 12, accentWidth: 4, closeSize: 16, minW: 280},
    lg: {paddingV: 16, paddingH: 18, summarySize: 16, bodySize: 14, accentWidth: 5, closeSize: 18, minW: 320},
};

const KitsToast = ({ref}: { ref?: Ref<IKitsToastRef> }) => {
    const [toasts, setToasts] = useState<ToastItem[]>([]);
    const timersRef = useRef<Map<number, ReturnType<typeof setTimeout>>>(new Map());
    const {resolveToken} = useKitsTheme();
    const insets = useSafeAreaInsets();

    const severityColors: Record<string, string> = {
        success: resolveToken('green.500'),
        info: resolveToken('blue.500'),
        warn: resolveToken('yellow.500'),
        error: resolveToken('red.500'),
        loading: resolveToken('blue.500'),
        brand: resolveToken('primary'),
    };

    const surfaceColor = resolveToken('surface-card');
    const textColor = resolveToken('text');
    const borderColor = resolveToken('border');

    const removeToast = useCallback((id: number) => {
        const timer = timersRef.current.get(id);
        if (timer) {
            clearTimeout(timer);
            timersRef.current.delete(id);
        }
        setToasts(prev => prev.filter(t => t.id !== id));
    }, []);

    const toast: IToastFunction = useCallback((
        severity: ToastSeverity,
        summary: string,
        body: string = "",
        position: ToastPosition = "bottom-center",
        _isUpdate: boolean = false,
        size: ToastSize = "md",
    ) => {
        const id = ++toastIdCounter;
        const item: ToastItem = {id, severity, summary, body, position, size, sticky: severity === "loading"};

        setToasts(prev => [...prev, item]);

        if (!item.sticky) {
            const timer = setTimeout(() => removeToast(id), LIFE);
            timersRef.current.set(id, timer);
        }
    }, [removeToast]) as IToastFunction;

    const dismiss = useCallback((position?: ToastPosition) => {
        setToasts(prev => {
            const toRemove = position ? prev.filter(t => t.position === position) : prev;
            toRemove.forEach(t => {
                const timer = timersRef.current.get(t.id);
                if (timer) {
                    clearTimeout(timer);
                    timersRef.current.delete(t.id);
                }
            });
            return position ? prev.filter(t => t.position !== position) : [];
        });
    }, []);

    const dismissAll = useCallback(() => {
        timersRef.current.forEach(t => clearTimeout(t));
        timersRef.current.clear();
        setToasts([]);
    }, []);

    useImperativeHandle(ref, () => ({toast, dismiss, dismissAll}));

    useEffect(() => {
        return () => {
            timersRef.current.forEach(t => clearTimeout(t));
        };
    }, []);

    if (toasts.length === 0) return null;

    const getAlignment = (position: ToastPosition): 'flex-start' | 'center' | 'flex-end' => {
        if (position.endsWith('-left')) return 'flex-start';
        if (position.endsWith('-right')) return 'flex-end';
        return 'center';
    };

    const isTop = (position: ToastPosition) => position.startsWith('top');

    return (
        <View style={StyleSheet.absoluteFill} pointerEvents="box-none">
            {toasts.map(item => {
                const top = isTop(item.position);
                const align = getAlignment(item.position);
                const entering = top ? SlideInUp.duration(300) : SlideInDown.duration(300);
                const exiting = top ? SlideOutUp.duration(200) : SlideOutDown.duration(200);
                const s = SIZE_CONFIG[item.size] ?? SIZE_CONFIG.md;
                const accentColor = severityColors[item.severity] ?? severityColors.info;

                return (
                    <Animated.View
                        key={item.id}
                        entering={entering}
                        exiting={exiting}
                        layout={Layout.duration(200)}
                        style={[
                            styles.toastWrapper,
                            {
                                alignItems: align,
                                ...(top
                                    ? {top: insets.top + 8}
                                    : {bottom: insets.bottom + 8}),
                            },
                        ]}
                        pointerEvents="box-none"
                    >
                        <Animated.View
                            entering={FadeIn.duration(200)}
                            exiting={FadeOut.duration(150)}
                            style={[
                                styles.toast,
                                {
                                    backgroundColor: surfaceColor,
                                    borderColor,
                                    minWidth: s.minW,
                                },
                            ]}
                        >
                            <View style={[styles.accentBar, {backgroundColor: accentColor, width: s.accentWidth}]}/>
                            <View style={[styles.content, {paddingVertical: s.paddingV, paddingHorizontal: s.paddingH, gap: s.paddingH * 0.7}]}>
                                {item.severity === "loading" && (
                                    <ActivityIndicator size="small" color={accentColor}/>
                                )}
                                <View style={styles.textContainer}>
                                    <Text style={{fontWeight: "600", fontSize: s.summarySize, color: textColor}}>
                                        {item.summary}
                                    </Text>
                                    {!!item.body && (
                                        <Text style={{fontSize: s.bodySize, marginTop: 2, color: textColor, opacity: 0.7}}>
                                            {item.body}
                                        </Text>
                                    )}
                                </View>
                                <Pressable onPress={() => removeToast(item.id)} hitSlop={8}>
                                    <Text style={{fontSize: s.closeSize, fontWeight: "bold", color: textColor, opacity: 0.4}}>
                                        ✕
                                    </Text>
                                </Pressable>
                            </View>
                        </Animated.View>
                    </Animated.View>
                );
            })}
        </View>
    );
};

const styles = StyleSheet.create({
    toastWrapper: {
        position: "absolute",
        left: 16,
        right: 16,
        zIndex: 9999,
    },
    toast: {
        flexDirection: "row",
        borderRadius: 10,
        borderWidth: 1,
        marginBottom: 8,
        overflow: "hidden",
        elevation: 6,
        shadowColor: "#000",
        shadowOffset: {width: 0, height: 3},
        shadowOpacity: 0.15,
        shadowRadius: 6,
    },
    accentBar: {},
    content: {
        flex: 1,
        flexDirection: "row",
        alignItems: "center",
    },
    textContainer: {
        flex: 1,
    },
});

export default KitsToast;
